const bridgeBaseUrl = process.env.RECALL_BRIDGE_BASE_URL || 'http://100.116.103.78:8090';
const bridgeApiKey = process.env.RECALL_API_KEY || '';
const similarityThreshold = 0.92;
const delayMsBetweenCompanies = 2000;

const companies = [
  { name: 'Anthropic', tier: 2, ats: 'greenhouse', boardId: 'anthropic', titleFilter: ['solutions', 'engineer', 'architect', 'technical', 'account', 'sales'] },
  { name: 'OpenAI', tier: 2, ats: 'greenhouse', boardId: 'openai', titleFilter: ['solutions', 'engineer', 'architect', 'sales'] },
  { name: 'Postman', tier: 1, ats: 'greenhouse', boardId: 'postman', titleFilter: ['solutions', 'engineer', 'architect', 'technical'] },
  { name: 'Aisera', tier: 1, ats: 'greenhouse', boardId: 'aisera', titleFilter: ['solutions', 'engineer', 'sales', 'architect'] },
  { name: 'Miro', tier: 1, ats: 'greenhouse', boardId: 'miro', titleFilter: ['solutions', 'engineer', 'architect', 'customer'] },
  { name: 'Airtable', tier: 1, ats: 'greenhouse', boardId: 'airtable', titleFilter: ['solutions', 'engineer', 'architect', 'technical account'] },
  { name: 'Smartsheet', tier: 1, ats: 'greenhouse', boardId: 'smartsheet', titleFilter: ['solutions', 'engineer', 'architect', 'customer'] },
  { name: 'Cohere', tier: 2, ats: 'greenhouse', boardId: 'cohere', titleFilter: ['solutions', 'engineer', 'architect', 'technical account'] },
  { name: 'Glean', tier: 2, ats: 'greenhouse', boardId: 'gleanwork', titleFilter: ['solutions', 'engineer', 'architect', 'customer'] },
  { name: 'Writer', tier: 2, ats: 'greenhouse', boardId: 'writer', titleFilter: ['solutions', 'engineer', 'architect', 'sales'] },
  { name: 'Atlassian', tier: 2, ats: 'greenhouse', boardId: 'atlassian', titleFilter: ['solutions', 'developer', 'architect', 'technical account'] },
  { name: 'Workato', tier: 2, ats: 'greenhouse', boardId: 'workato', titleFilter: ['solutions', 'engineer', 'architect', 'automation'] },
  { name: 'Datadog', tier: 2, ats: 'greenhouse', boardId: 'datadog', titleFilter: ['solutions', 'engineer', 'architect', 'technical account'] }
];

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function normalizeText(value) {
  return String(value || '').trim();
}

function titleMatchesFilters(title, filters) {
  const normalizedTitle = normalizeText(title).toLowerCase();
  if (!normalizedTitle) return false;
  if (!Array.isArray(filters) || filters.length === 0) return true;
  return filters.some((token) => normalizedTitle.includes(String(token || '').toLowerCase()));
}

async function fetchJson(url, options = {}) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 30000);
  try {
    const response = await fetch(url, {
      ...options,
      signal: controller.signal,
      headers: {
        'accept': 'application/json',
        ...(options.headers || {}),
      },
    });
    const raw = await response.text();
    let parsed;
    try {
      parsed = raw ? JSON.parse(raw) : {};
    } catch (err) {
      parsed = { raw };
    }
    if (!response.ok) {
      throw new Error('HTTP ' + response.status + ' from ' + url + ': ' + raw);
    }
    return parsed;
  } finally {
    clearTimeout(timeout);
  }
}

const bridgeHeaders = {
  'content-type': 'application/json',
};
if (bridgeApiKey) {
  bridgeHeaders['x-api-key'] = bridgeApiKey;
}

const startedAt = new Date().toISOString();
const summaries = [];
let totalFetched = 0;
let totalFiltered = 0;
let totalNew = 0;
let totalDuplicates = 0;
const allNewJobIds = [];
const allErrors = [];

for (const company of companies) {
  const companySummary = {
    company: company.name,
    ats: company.ats,
    fetched: 0,
    matched: 0,
    new_jobs: 0,
    duplicates_skipped: 0,
    errors: [],
  };

  try {
    let sourceJobs = [];

    if (company.ats === 'greenhouse') {
      const url = 'https://boards-api.greenhouse.io/v1/boards/' + encodeURIComponent(company.boardId) + '/jobs';
      const payload = await fetchJson(url);
      sourceJobs = Array.isArray(payload.jobs) ? payload.jobs : [];
      companySummary.fetched = sourceJobs.length;

      const normalizedJobs = sourceJobs
        .filter((job) => titleMatchesFilters(job.title, company.titleFilter))
        .map((job) => ({
          title: normalizeText(job.title),
          company: company.name,
          location: normalizeText(job.location && job.location.name),
          url: normalizeText(job.absolute_url),
          description: '',
          source: 'career_page',
          search_query: company.name + ' careers',
          company_tier: company.tier,
          date_posted: job.updated_at || null,
        }));

      companySummary.matched = normalizedJobs.length;
      totalFetched += companySummary.fetched;
      totalFiltered += companySummary.matched;

      if (normalizedJobs.length > 0) {
        const discoveryResult = await fetchJson(bridgeBaseUrl + '/v1/job-discovery-runs', {
          method: 'POST',
          headers: bridgeHeaders,
          body: JSON.stringify({
            sources: ['career_page'],
            jobs: normalizedJobs,
            dry_run: false,
            similarity_threshold: similarityThreshold,
          }),
        });

        const newJobIds = Array.isArray(discoveryResult.new_job_ids) ? discoveryResult.new_job_ids : [];
        companySummary.new_jobs = newJobIds.length;
        companySummary.duplicates_skipped = Number(discoveryResult.duplicates_skipped || 0);
        companySummary.discovery_run_id = discoveryResult.run_id || null;
        companySummary.discovery_errors = Array.isArray(discoveryResult.errors) ? discoveryResult.errors : [];

        totalNew += companySummary.new_jobs;
        totalDuplicates += companySummary.duplicates_skipped;
        allNewJobIds.push(...newJobIds);

        if (newJobIds.length > 0) {
          const evalResult = await fetchJson(bridgeBaseUrl + '/v1/job-evaluation-runs', {
            method: 'POST',
            headers: bridgeHeaders,
            body: JSON.stringify({ job_ids: newJobIds, wait: false }),
          });
          companySummary.evaluation_run_id = evalResult.run_id || null;
        }
      }
    } else if (company.ats === 'lever') {
      const url = 'https://api.lever.co/v0/postings/' + encodeURIComponent(company.boardId) + '?mode=json';
      const payload = await fetchJson(url);
      sourceJobs = Array.isArray(payload) ? payload : [];
      companySummary.fetched = sourceJobs.length;

      const normalizedJobs = sourceJobs
        .filter((job) => titleMatchesFilters(job.text, company.titleFilter))
        .map((job) => ({
          title: normalizeText(job.text),
          company: company.name,
          location: normalizeText(job.categories && job.categories.location),
          url: normalizeText(job.hostedUrl),
          description: normalizeText(job.descriptionPlain || job.description),
          source: 'career_page',
          search_query: company.name + ' careers',
          company_tier: company.tier,
          date_posted: job.createdAt || null,
        }));

      companySummary.matched = normalizedJobs.length;
      totalFetched += companySummary.fetched;
      totalFiltered += companySummary.matched;

      if (normalizedJobs.length > 0) {
        const discoveryResult = await fetchJson(bridgeBaseUrl + '/v1/job-discovery-runs', {
          method: 'POST',
          headers: bridgeHeaders,
          body: JSON.stringify({
            sources: ['career_page'],
            jobs: normalizedJobs,
            dry_run: false,
            similarity_threshold: similarityThreshold,
          }),
        });

        const newJobIds = Array.isArray(discoveryResult.new_job_ids) ? discoveryResult.new_job_ids : [];
        companySummary.new_jobs = newJobIds.length;
        companySummary.duplicates_skipped = Number(discoveryResult.duplicates_skipped || 0);
        companySummary.discovery_run_id = discoveryResult.run_id || null;
        companySummary.discovery_errors = Array.isArray(discoveryResult.errors) ? discoveryResult.errors : [];

        totalNew += companySummary.new_jobs;
        totalDuplicates += companySummary.duplicates_skipped;
        allNewJobIds.push(...newJobIds);

        if (newJobIds.length > 0) {
          const evalResult = await fetchJson(bridgeBaseUrl + '/v1/job-evaluation-runs', {
            method: 'POST',
            headers: bridgeHeaders,
            body: JSON.stringify({ job_ids: newJobIds, wait: false }),
          });
          companySummary.evaluation_run_id = evalResult.run_id || null;
        }
      }
    } else {
      companySummary.errors.push('Unsupported ATS: ' + company.ats);
    }
  } catch (err) {
    const message = err && err.message ? err.message : String(err);
    companySummary.errors.push(message);
    allErrors.push(company.name + ': ' + message);
  }

  summaries.push(companySummary);
  await sleep(delayMsBetweenCompanies);
}

return [
  {
    json: {
      workflow: 'workflow_06b_career_page_monitor',
      status: allErrors.length > 0 ? 'partial' : 'completed',
      started_at: startedAt,
      finished_at: new Date().toISOString(),
      total_companies: companies.length,
      totals: {
        fetched_jobs: totalFetched,
        matched_jobs: totalFiltered,
        new_jobs: totalNew,
        duplicates_skipped: totalDuplicates,
      },
      new_job_ids: allNewJobIds,
      companies: summaries,
      errors: allErrors,
      message: 'Career monitor processed ' + companies.length + ' companies; new jobs: ' + totalNew + '.',
    },
  },
];
